import { useMemo, useState } from "react";
import axios from "axios";

const API_URL = "http://localhost:8000/ask";

function App() {
  const [url, setUrl] = useState("");
  const [customText, setCustomText] = useState("");
  const [question, setQuestion] = useState("");
  const [sessionId, setSessionId] = useState("");
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const canSend = useMemo(() => question.trim().length > 0 && !loading, [question, loading]);

  const handleSend = async () => {
    const trimmedQuestion = question.trim();
    if (!trimmedQuestion || loading) {
      return;
    }

    setError("");
    setLoading(true);
    setMessages((prev) => [...prev, { role: "user", content: trimmedQuestion }]);

    const payload = {
      question: trimmedQuestion,
      ...(sessionId ? { session_id: sessionId } : {}),
      ...(!sessionId && url.trim() ? { url: url.trim() } : {}),
      ...(!sessionId && customText.trim() ? { text: customText.trim() } : {})
    };

    try {
      const response = await axios.post(API_URL, payload, {
        headers: { "Content-Type": "application/json" }
      });
      const { session_id, answer } = response.data;
      setSessionId(session_id);
      setMessages((prev) => [...prev, { role: "assistant", content: answer }]);
      setQuestion("");
    } catch (err) {
      const detail = err?.response?.data?.detail || "Failed to get response from server.";
      setError(detail);
      setMessages((prev) => [...prev, { role: "assistant", content: "Error: " + detail }]);
    } finally {
      setLoading(false);
    }
  };

  const handleKeyDown = (event) => {
    if (event.key === "Enter" && !event.shiftKey) {
      event.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="page">
      <div className="shell">
        <header className="topbar">
          <h1>Context-Aware AI Chatbot</h1>
          <p>React + FastAPI + Ollama ({sessionId ? `Session: ${sessionId}` : "No session yet"})</p>
        </header>

        <section className="inputs">
          <label>
            Website URL (optional, first message only)
            <input
              type="url"
              placeholder="https://example.com"
              value={url}
              onChange={(e) => setUrl(e.target.value)}
              disabled={loading || !!sessionId}
            />
          </label>

          <label>
            Custom Text (optional, first message only)
            <textarea
              placeholder="Paste additional context..."
              value={customText}
              onChange={(e) => setCustomText(e.target.value)}
              disabled={loading || !!sessionId}
              rows={4}
            />
          </label>
        </section>

        <section className="chat">
          <div className="messages">
            {messages.length === 0 && (
              <div className="empty">Ask a question to start the conversation.</div>
            )}
            {messages.map((msg, index) => (
              <div key={`${msg.role}-${index}`} className={`msg msg-${msg.role}`}>
                <div className="badge">{msg.role === "user" ? "You" : "Assistant"}</div>
                <div className="bubble">{msg.content}</div>
              </div>
            ))}
            {loading && <div className="loading">Thinking...</div>}
          </div>

          <div className="composer">
            <textarea
              placeholder="Ask a question..."
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              onKeyDown={handleKeyDown}
              rows={3}
              disabled={loading}
            />
            <button onClick={handleSend} disabled={!canSend}>
              Send
            </button>
          </div>
        </section>

        {error && <div className="error">{error}</div>}
      </div>
    </div>
  );
}

export default App;
